'use strict';

const express = require('express');
const crypto = require('crypto');

const app = express();
const PORT = 3000;

// Use express.raw middleware ONLY for the /webhook route so the exact raw
// request body bytes are preserved for HMAC computation.
app.post(
  '/webhook',
  express.raw({ type: 'application/json' }),
  (req, res) => {
    const receivedSignature = req.headers['x-prembly-signature'];

    // Reject immediately if the signature header is absent.
    if (!receivedSignature) {
      return res.status(401).json({ error: 'Invalid signature' });
    }

    const apiKey = process.env.PREMBLY_API_KEY;

    // Compute HMAC-SHA256 of the raw body, Base64-encoded.
    const computedSignature = crypto
      .createHmac('sha256', apiKey)
      .update(req.body)
      .digest('base64');

    // Use timingSafeEqual to prevent timing-attack leakage.
    const received = Buffer.from(receivedSignature);
    const computed = Buffer.from(computedSignature);

    const signaturesMatch =
      received.length === computed.length &&
      crypto.timingSafeEqual(received, computed);

    if (!signaturesMatch) {
      return res.status(401).json({ error: 'Invalid signature' });
    }

    return res.status(200).json({ status: 'success' });
  }
);

app.listen(PORT, () => {
  console.log(`Prembly webhook server listening on port ${PORT}`);
});
